/**
 * Session Upload CLI
 *
 * CLI tool to upload a session by ID.
 *
 * Usage: bun run session-upload-cli.ts <session-id>
 *
 * Logs are written to: ~/.claude/logs/session-upload.log
 */

import { getLogger } from "@logtape/logtape";
import {
  uploadSession,
  readTranscript,
  findSessionById,
  extractAgentIds,
  readSubagentFiles,
  getRepositoryName,
  type IngestRequest,
} from "./lib/session-upload-core";

const logger = getLogger(["compound", "session-upload"]);

async function main(): Promise<void> {
  const sessionId = process.argv[2];

  if (!sessionId) {
    console.error("Usage: bun run session-upload-cli.ts <session-id>");
    process.exit(1);
  }

  logger.debug("Session upload CLI started for session {sessionId}", {
    sessionId,
  });

  console.log(`Looking for session: ${sessionId}`);

  const sessionInfo = await findSessionById(sessionId);
  if (!sessionInfo) {
    console.error(`Session not found: ${sessionId}`);
    process.exit(1);
  }

  console.log(`Found session at: ${sessionInfo.transcriptPath}`);

  const content = await readTranscript(sessionInfo.transcriptPath);
  if (!content) {
    console.error("Failed to read transcript");
    process.exit(1);
  }

  console.log(`Read transcript: ${content.length} bytes`);

  // Extract and read subagent files
  const agentIds = extractAgentIds(content);
  let subagents;
  if (agentIds.length > 0) {
    console.log(`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`);
    subagents = await readSubagentFiles(sessionInfo.sessionDir, agentIds, sessionId);
    console.log(
      `Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`
    );
  }

  // Get repository name from project path
  const repository = await getRepositoryName(sessionInfo.projectPath);
  if (repository) {
    console.log(`Repository: ${repository}`);
  } else {
    console.log("Could not determine repository name");
  }

  const request: IngestRequest = {
    sessionId,
    projectPath: sessionInfo.projectPath,
    repository: repository ?? undefined,
    content,
    subagents: subagents?.length ? subagents : undefined,
  };

  console.log("Uploading session...");
  const result = await uploadSession(request);

  if (result.success) {
    console.log("Upload successful");
  } else {
    console.error(`Upload failed: ${result.error}`);
    process.exit(1);
  }
}

main();

