     1→/**
     2→ * Session Upload Core
     3→ *
     4→ * Shared logic for uploading Claude Code session transcripts to the backend.
     5→ */
     6→
     7→import { configureSync, getLogger } from "@logtape/logtape";
     8→import { getFileSink } from "@logtape/file";
     9→import { homedir } from "os";
    10→import { join, dirname } from "path";
    11→import { readdir } from "fs/promises";
    12→import { $ } from "bun";
    13→
    14→// Constants
    15→const LOG_DIR = join(homedir(), ".claude", "logs");
    16→const LOG_FILE = join(LOG_DIR, "session-upload.log");
    17→const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");
    18→
    19→export const INGEST_ENDPOINT =
    20→  "https://flick-api.numia.workers.dev/api/orpc/compound/ingestSession";
    21→// export const INGEST_ENDPOINT =
    22→//   "http://localhost:8731/api/orpc/compound/ingestSession";
    23→
    24→// Types
    25→export interface SubagentFile {
    26→  agentId: string;
    27→  content: string;
    28→}
    29→
    30→/** Session classification tags */
    31→export type SessionTag =
    32→  | "research"
    33→  | "new_feature"
    34→  | "bug_fix"
    35→  | "refactoring"
    36→  | "documentation"
    37→  | "tests"
    38→  | "other";
    39→
    40→export interface IngestRequest {
    41→  sessionId: string;
    42→  projectPath: string;
    43→  /** Repository name from package.json or git remote (more stable than path) */
    44→  repository?: string;
    45→  /** Current git branch */
    46→  gitBranch?: string;
    47→  /** Current git commit SHA */
    48→  gitSha?: string;
    49→  /** Session classification tag */
    50→  tag?: SessionTag;
    51→  content: string;
    52→  subagents?: SubagentFile[];
    53→}
    54→
    55→export interface UploadResult {
    56→  success: boolean;
    57→  error?: string;
    58→}
    59→
    60→configureSync({
    61→  sinks: {
    62→    file: getFileSink(LOG_FILE, {
    63→      lazy: true,
    64→      bufferSize: 0,
    65→    }),
    66→  },
    67→  loggers: [
    68→    {
    69→      category: ["compound", "session-upload"],
    70→      lowestLevel: "debug",
    71→      sinks: ["file"],
    72→    },
    73→  ],
    74→});
    75→
    76→const logger = getLogger(["compound", "session-upload"]);
    77→
    78→/**
    79→ * Upload a session transcript to the backend
    80→ */
    81→export async function uploadSession(
    82→  request: IngestRequest
    83→): Promise<UploadResult> {
    84→  const apiKey = process.env.FLICK_COMPOUND_API_KEY;
    85→
    86→  if (!apiKey) {
    87→    logger.debug("No FLICK_COMPOUND_API_KEY configured, skipping upload");
    88→    return { success: false, error: "No API key configured" };
    89→  }
    90→
    91→  logger.info("Uploading session {sessionId} ({bytes} bytes), tag={tag}", {
    92→    sessionId: request.sessionId,
    93→    bytes: request.content.length,
    94→    tag: request.tag ?? "NOT_SET",
    95→  });
    96→
    97→  try {
    98→    // Log which fields are present in the request (excluding content for brevity)
    99→    const requestKeys = Object.keys(request).filter(k => k !== "content" && k !== "subagents");
   100→    const requestDebug = Object.fromEntries(
   101→      requestKeys.map(k => [k, (request as unknown as Record<string, unknown>)[k]])
   102→    );
   103→    logger.debug("Request fields being sent: {fields}", { fields: JSON.stringify(requestDebug) });
   104→
   105→    const response = await fetch(INGEST_ENDPOINT, {
   106→      method: "POST",
   107→      headers: {
   108→        "Content-Type": "application/json",
   109→        "x-api-key": apiKey,
   110→      },
   111→      body: JSON.stringify(request),
   112→    });
   113→
   114→    const responseText = await response.text();
   115→
   116→    if (!response.ok) {
   117→      logger.error("Upload failed ({status}): {error}", {
   118→        status: response.status,
   119→        error: responseText,
   120→      });
   121→      return { success: false, error: `HTTP ${response.status}: ${responseText}` };
   122→    }
   123→
   124→    logger.info("Upload successful for session {sessionId}, status={status}, response={response}", {
   125→      sessionId: request.sessionId,
   126→      status: response.status,
   127→      response: responseText.slice(0, 200),
   128→    });
   129→    return { success: true };
   130→  } catch (error) {
   131→    logger.error("Upload error: {error}", { error });
   132→    return { success: false, error: String(error) };
   133→  }
   134→}
   135→
   136→export interface SessionInfo {
   137→  transcriptPath: string;
   138→  projectPath: string;
   139→  /** Directory containing the session file (for finding subagent files) */
   140→  sessionDir: string;
   141→}
   142→
   143→/**
   144→ * Decode an encoded project directory name back to the actual filesystem path.
   145→ * Handles directory names that contain dashes by checking if paths exist.
   146→ *
   147→ * Example: "-Users-marc-Workspace-claude-marketplace" -> "/Users/marc/Workspace/claude-marketplace"
   148→ */
   149→async function decodeProjectPath(encodedDir: string): Promise<string> {
   150→  // Remove leading dash and split by dash
   151→  const parts = encodedDir.replace(/^-/, "").split("-");
   152→
   153→  // Recursive function to find the valid path
   154→  async function findPath(
   155→    partIndex: number,
   156→    currentPath: string
   157→  ): Promise<string | null> {
   158→    if (partIndex >= parts.length) {
   159→      // Check if this is the final valid path
   160→      try {
   161→        const stat = await Bun.file(currentPath).stat();
   162→        if (stat !== null) {
   163→          return currentPath;
   164→        }
   165→      } catch {
   166→        // Path doesn't exist
   167→      }
   168→      return null;
   169→    }
   170→
   171→    // Try consuming multiple parts with dashes (greedy - try longest first)
   172→    for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
   173→      const segment = parts.slice(partIndex, endIndex).join("-");
   174→      const testPath = currentPath
   175→        ? `${currentPath}/${segment}`
   176→        : `/${segment}`;
   177→
   178→      // Check if this path exists
   179→      try {
   180→        const stat = await Bun.file(testPath).stat();
   181→        if (stat !== null) {
   182→          // If we've consumed all parts and path exists, return it
   183→          if (endIndex === parts.length) {
   184→            return testPath;
   185→          }
   186→          // Otherwise, continue recursively
   187→          const result = await findPath(endIndex, testPath);
   188→          if (result) {
   189→            return result;
   190→          }
   191→        }
   192→      } catch {
   193→        // Path doesn't exist, try shorter segment
   194→      }
   195→    }
   196→
   197→    return null;
   198→  }
   199→
   200→  const result = await findPath(0, "");
   201→  if (result) {
   202→    return result;
   203→  }
   204→
   205→  // Fallback: simple dash-to-slash replacement
   206→  return "/" + parts.join("/");
   207→}
   208→
   209→/**
   210→ * Find a session by ID and return its transcript path and project path
   211→ */
   212→export async function findSessionById(
   213→  sessionId: string
   214→): Promise<SessionInfo | null> {
   215→  try {
   216→    const projectDirs = await readdir(SESSIONS_BASE_DIR);
   217→    const sessionFileName = `${sessionId}.jsonl`;
   218→
   219→    for (const projectDir of projectDirs) {
   220→      const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
   221→      try {
   222→        const files = await readdir(sessionDir);
   223→        if (files.includes(sessionFileName)) {
   224→          const transcriptPath = join(sessionDir, sessionFileName);
   225→
   226→          // Decode the encoded project directory to the actual filesystem path
   227→          const actualProjectPath = await decodeProjectPath(projectDir);
   228→
   229→          logger.debug("Found session {sessionId} at {path}", {
   230→            sessionId,
   231→            path: transcriptPath,
   232→          });
   233→          return { transcriptPath, projectPath: actualProjectPath, sessionDir };
   234→        }
   235→      } catch {
   236→        // Can't read this project directory
   237→        continue;
   238→      }
   239→    }
   240→
   241→    logger.error("Session {sessionId} not found", { sessionId });
   242→    return null;
   243→  } catch (error) {
   244→    logger.error("Error searching for session: {error}", { error });
   245→    return null;
   246→  }
   247→}
   248→
   249→// Utility Functions
   250→
   251→/**
   252→ * Read transcript file content with retry for timing issues
   253→ */
   254→export async function readTranscript(
   255→  transcriptPath: string
   256→): Promise<string | null> {
   257→  const maxRetries = 5;
   258→  const delayMs = 500;
   259→
   260→  for (let attempt = 1; attempt <= maxRetries; attempt++) {
   261→    try {
   262→      const file = Bun.file(transcriptPath);
   263→      const exists = await file.exists();
   264→      if (!exists) {
   265→        if (attempt < maxRetries) {
   266→          logger.debug(
   267→            "Transcript file not found (attempt {attempt}/{max}), retrying in {delay}ms: {path}",
   268→            { attempt, max: maxRetries, delay: delayMs, path: transcriptPath }
   269→          );
   270→          await new Promise((resolve) => setTimeout(resolve, delayMs));
   271→          continue;
   272→        }
   273→        logger.error("Transcript file not found after {max} attempts: {path}", {
   274→          max: maxRetries,
   275→          path: transcriptPath,
   276→        });
   277→        return null;
   278→      }
   279→      const content = await file.text();
   280→      logger.debug("Read transcript: {bytes} bytes", { bytes: content.length });
   281→      return content;
   282→    } catch (error) {
   283→      if (attempt < maxRetries) {
   284→        logger.debug("Failed to read transcript (attempt {attempt}), retrying: {error}", {
   285→          attempt,
   286→          error,
   287→        });
   288→        await new Promise((resolve) => setTimeout(resolve, delayMs));
   289→        continue;
   290→      }
   291→      logger.error("Failed to read transcript: {error}", { error });
   292→      return null;
   293→    }
   294→  }
   295→  return null;
   296→}
   297→
   298→/**
   299→ * Extract agent IDs referenced in a session transcript.
   300→ * Agents are spawned via the Task tool and their IDs are recorded in toolUseResult.agentId
   301→ */
   302→export function extractAgentIds(sessionContent: string): string[] {
   303→  const agentIds = new Set<string>();
   304→
   305→  for (const line of sessionContent.split("\n")) {
   306→    if (!line.trim()) continue;
   307→
   308→    try {
   309→      const entry = JSON.parse(line);
   310→      // Agent IDs appear in toolUseResult.agentId when Task tool completes
   311→      if (entry.toolUseResult?.agentId) {
   312→        agentIds.add(entry.toolUseResult.agentId);
   313→      }
   314→    } catch {
   315→      // Skip malformed lines
   316→    }
   317→  }
   318→
   319→  const ids = Array.from(agentIds);
   320→  logger.debug("Found {count} subagent(s) in session: {ids}", {
   321→    count: ids.length,
   322→    ids: ids.join(", "),
   323→  });
   324→  return ids;
   325→}
   326→
   327→/**
   328→ * Read all subagent files for a session.
   329→ * Subagent transcripts can be stored in multiple locations:
   330→ * 1. {sessionDir}/agent-{agentId}.jsonl (legacy)
   331→ * 2. {sessionDir}/{sessionId}/subagents/agent-{agentId}.jsonl (new format)
   332→ */
   333→export async function readSubagentFiles(
   334→  sessionDir: string,
   335→  agentIds: string[],
   336→  sessionId?: string
   337→): Promise<SubagentFile[]> {
   338→  const subagents: SubagentFile[] = [];
   339→
   340→  for (const agentId of agentIds) {
   341→    // Try multiple locations for the subagent file
   342→    const possiblePaths = [
   343→      join(sessionDir, `agent-${agentId}.jsonl`),
   344→      ...(sessionId
   345→        ? [join(sessionDir, sessionId, "subagents", `agent-${agentId}.jsonl`)]
   346→        : []),
   347→    ];
   348→
   349→    let found = false;
   350→    for (const agentPath of possiblePaths) {
   351→      try {
   352→        const file = Bun.file(agentPath);
   353→        if (await file.exists()) {
   354→          const content = await file.text();
   355→          subagents.push({ agentId, content });
   356→          logger.debug("Read subagent {agentId}: {bytes} bytes from {path}", {
   357→            agentId,
   358→            bytes: content.length,
   359→            path: agentPath,
   360→          });
   361→          found = true;
   362→          break;
   363→        }
   364→      } catch {
   365→        // Try next path
   366→      }
   367→    }
   368→
   369→    if (!found) {
   370→      logger.warn("Subagent file not found for {agentId}", { agentId });
   371→    }
   372→  }
   373→
   374→  return subagents;
   375→}
   376→
   377→/**
   378→ * Get the repository name for a given directory.
   379→ * Looks for the git root, then reads package.json name or extracts from git remote.
   380→ */
   381→export async function getRepositoryName(cwd: string): Promise<string | null> {
   382→  try {
   383→    // Find git root directory
   384→    const gitRootResult =
   385→      await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
   386→    if (gitRootResult.exitCode !== 0) {
   387→      logger.debug("Not a git repository: {cwd}", { cwd });
   388→      return null;
   389→    }
   390→    const gitRoot = gitRootResult.text().trim();
   391→    logger.info("Git root: {gitRoot}", { gitRoot });
   392→
   393→    // Try package.json name first
   394→    const packageJsonPath = join(gitRoot, "package.json");
   395→    const packageFile = Bun.file(packageJsonPath);
   396→    if (await packageFile.exists()) {
   397→      try {
   398→        const packageJson = await packageFile.json();
   399→        if (packageJson.name) {
   400→          logger.debug("Found repository name from package.json: {name}", {
   401→            name: packageJson.name,
   402→          });
   403→          return packageJson.name;
   404→        }
   405→      } catch {
   406→        // Invalid JSON, continue to git remote
   407→      }
   408→    }
   409→
   410→    // Fall back to git remote origin URL
   411→    const remoteResult =
   412→      await $`git -C ${gitRoot} remote get-url origin`.quiet();
   413→    if (remoteResult.exitCode === 0) {
   414→      const remoteUrl = remoteResult.text().trim();
   415→      // Extract repo name from various URL formats:
   416→      // - git@github.com:org/repo.git -> repo
   417→      // - https://github.com/org/repo.git -> repo
   418→      // - https://github.com/org/repo -> repo
   419→      const match = remoteUrl.match(/[/:]([^/]+?)(?:\.git)?$/);
   420→      if (match?.[1]) {
   421→        logger.debug("Found repository name from git remote: {name}", {
   422→          name: match[1],
   423→        });
   424→        return match[1];
   425→      }
   426→    }
   427→
   428→    // Fall back to directory name
   429→    const dirName = gitRoot.split("/").pop();
   430→    if (dirName) {
   431→      logger.debug("Using directory name as repository: {name}", {
   432→        name: dirName,
   433→      });
   434→      return dirName;
   435→    }
   436→
   437→    return null;
   438→  } catch (error) {
   439→    logger.error("Failed to get repository name: {error}", { error });
   440→    return null;
   441→  }
   442→}
   443→
   444→/**
   445→ * Get the current git branch name for a given directory.
   446→ */
   447→export async function getGitBranch(cwd: string): Promise<string | null> {
   448→  try {
   449→    const result = await $`git -C ${cwd} rev-parse --abbrev-ref HEAD`.quiet();
   450→    if (result.exitCode !== 0) {
   451→      return null;
   452→    }
   453→    const branch = result.text().trim();
   454→    logger.debug("Git branch: {branch}", { branch });
   455→    return branch;
   456→  } catch (error) {
   457→    logger.error("Failed to get git branch: {error}", { error });
   458→    return null;
   459→  }
   460→}
   461→
   462→/**
   463→ * Get the current git commit SHA for a given directory.
   464→ */
   465→export async function getGitSha(cwd: string): Promise<string | null> {
   466→  try {
   467→    const result = await $`git -C ${cwd} rev-parse HEAD`.quiet();
   468→    if (result.exitCode !== 0) {
   469→      return null;
   470→    }
   471→    const sha = result.text().trim();
   472→    logger.debug("Git SHA: {sha}", { sha });
   473→    return sha;
   474→  } catch (error) {
   475→    logger.error("Failed to get git SHA: {error}", { error });
   476→    return null;
   477→  }
   478→}
   479→
   480→const VALID_TAGS: SessionTag[] = [
   481→  "research",
   482→  "new_feature",
   483→  "bug_fix",
   484→  "refactoring",
   485→  "documentation",
   486→  "tests",
   487→  "other",
   488→];
   489→
   490→/**
   491→ * Classify a session transcript using Claude CLI.
   492→ * Returns one of the predefined tags based on the session content.
   493→ */
   494→export async function classifySession(
   495→  content: string
   496→): Promise<SessionTag | null> {
   497→  const systemPrompt = `You are a session classifier. Analyze the Claude Code session transcript and classify it into exactly ONE of these categories:
   498→
