/**
 * Session Upload Core
 *
 * Shared logic for uploading Claude Code session transcripts to the backend.
 */

import { configureSync, getLogger } from "@logtape/logtape";
import { getFileSink } from "@logtape/file";
import { homedir } from "os";
import { join, dirname } from "path";
import { readdir } from "fs/promises";
import { $ } from "bun";

// Constants
const LOG_DIR = join(homedir(), ".claude", "logs");
const LOG_FILE = join(LOG_DIR, "session-upload.log");
const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");

export const INGEST_ENDPOINT =
  "https://flick-api.numia.workers.dev/api/orpc/compound/ingestSession";
// export const INGEST_ENDPOINT =
//   "http://localhost:8731/api/orpc/compound/ingestSession";

// Types
export interface SubagentFile {
  agentId: string;
  content: string;
}

/** Session classification tags */
export type SessionTag =
  | "research"
  | "new_feature"
  | "bug_fix"
  | "refactoring"
  | "documentation"
  | "tests"
  | "other";

export interface IngestRequest {
  sessionId: string;
  projectPath: string;
  /** Repository name from package.json or git remote (more stable than path) */
  repository?: string;
  /** Current git branch */
  gitBranch?: string;
  /** Current git commit SHA */
  gitSha?: string;
  /** Session classification tag */
  tag?: SessionTag;
  content: string;
  subagents?: SubagentFile[];
}

export interface UploadResult {
  success: boolean;
  error?: string;
}

configureSync({
  sinks: {
    file: getFileSink(LOG_FILE, {
      lazy: true,
      bufferSize: 0,
    }),
  },
  loggers: [
    {
      category: ["compound", "session-upload"],
      lowestLevel: "debug",
      sinks: ["file"],
    },
  ],
});

const logger = getLogger(["compound", "session-upload"]);

/**
 * Upload a session transcript to the backend
 */
export async function uploadSession(
  request: IngestRequest
): Promise<UploadResult> {
  const apiKey = process.env.FLICK_COMPOUND_API_KEY;

  if (!apiKey) {
    logger.debug("No FLICK_COMPOUND_API_KEY configured, skipping upload");
    return { success: false, error: "No API key configured" };
  }

  logger.info("Uploading session {sessionId} ({bytes} bytes), tag={tag}", {
    sessionId: request.sessionId,
    bytes: request.content.length,
    tag: request.tag ?? "NOT_SET",
  });

  try {
    // Log which fields are present in the request (excluding content for brevity)
    const requestKeys = Object.keys(request).filter(k => k !== "content" && k !== "subagents");
    const requestDebug = Object.fromEntries(
      requestKeys.map(k => [k, (request as unknown as Record<string, unknown>)[k]])
    );
    logger.debug("Request fields being sent: {fields}", { fields: JSON.stringify(requestDebug) });

    const response = await fetch(INGEST_ENDPOINT, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": apiKey,
      },
      body: JSON.stringify(request),
    });

    const responseText = await response.text();

    if (!response.ok) {
      logger.error("Upload failed ({status}): {error}", {
        status: response.status,
        error: responseText,
      });
      return { success: false, error: `HTTP ${response.status}: ${responseText}` };
    }

    logger.info("Upload successful for session {sessionId}, status={status}, response={response}", {
      sessionId: request.sessionId,
      status: response.status,
      response: responseText.slice(0, 200),
    });
    return { success: true };
  } catch (error) {
    logger.error("Upload error: {error}", { error });
    return { success: false, error: String(error) };
  }
}

export interface SessionInfo {
  transcriptPath: string;
  projectPath: string;
  /** Directory containing the session file (for finding subagent files) */
  sessionDir: string;
}

/**
 * Decode an encoded project directory name back to the actual filesystem path.
 * Handles directory names that contain dashes by checking if paths exist.
 *
 * Example: "-Users-marc-Workspace-claude-marketplace" -> "/Users/marc/Workspace/claude-marketplace"
 */
async function decodeProjectPath(encodedDir: string): Promise<string> {
  // Remove leading dash and split by dash
  const parts = encodedDir.replace(/^-/, "").split("-");

  // Recursive function to find the valid path
  async function findPath(
    partIndex: number,
    currentPath: string
  ): Promise<string | null> {
    if (partIndex >= parts.length) {
      // Check if this is the final valid path
      try {
        const stat = await Bun.file(currentPath).stat();
        if (stat !== null) {
          return currentPath;
        }
      } catch {
        // Path doesn't exist
      }
      return null;
    }

    // Try consuming multiple parts with dashes (greedy - try longest first)
    for (let endIndex = parts.length; endIndex > partIndex; endIndex--) {
      const segment = parts.slice(partIndex, endIndex).join("-");
      const testPath = currentPath
        ? `${currentPath}/${segment}`
        : `/${segment}`;

      // Check if this path exists
      try {
        const stat = await Bun.file(testPath).stat();
        if (stat !== null) {
          // If we've consumed all parts and path exists, return it
          if (endIndex === parts.length) {
            return testPath;
          }
          // Otherwise, continue recursively
          const result = await findPath(endIndex, testPath);
          if (result) {
            return result;
          }
        }
      } catch {
        // Path doesn't exist, try shorter segment
      }
    }

    return null;
  }

  const result = await findPath(0, "");
  if (result) {
    return result;
  }

  // Fallback: simple dash-to-slash replacement
  return "/" + parts.join("/");
}

/**
 * Find a session by ID and return its transcript path and project path
 */
export async function findSessionById(
  sessionId: string
): Promise<SessionInfo | null> {
  try {
    const projectDirs = await readdir(SESSIONS_BASE_DIR);
    const sessionFileName = `${sessionId}.jsonl`;

    for (const projectDir of projectDirs) {
      const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
      try {
        const files = await readdir(sessionDir);
        if (files.includes(sessionFileName)) {
          const transcriptPath = join(sessionDir, sessionFileName);

          // Decode the encoded project directory to the actual filesystem path
          const actualProjectPath = await decodeProjectPath(projectDir);

          logger.debug("Found session {sessionId} at {path}", {
            sessionId,
            path: transcriptPath,
          });
          return { transcriptPath, projectPath: actualProjectPath, sessionDir };
        }
      } catch {
        // Can't read this project directory
        continue;
      }
    }

    logger.error("Session {sessionId} not found", { sessionId });
    return null;
  } catch (error) {
    logger.error("Error searching for session: {error}", { error });
    return null;
  }
}

// Utility Functions

/**
 * Read transcript file content with retry for timing issues
 */
export async function readTranscript(
  transcriptPath: string
): Promise<string | null> {
  const maxRetries = 5;
  const delayMs = 500;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const file = Bun.file(transcriptPath);
      const exists = await file.exists();
      if (!exists) {
        if (attempt < maxRetries) {
          logger.debug(
            "Transcript file not found (attempt {attempt}/{max}), retrying in {delay}ms: {path}",
            { attempt, max: maxRetries, delay: delayMs, path: transcriptPath }
          );
          await new Promise((resolve) => setTimeout(resolve, delayMs));
          continue;
        }
        logger.error("Transcript file not found after {max} attempts: {path}", {
          max: maxRetries,
          path: transcriptPath,
        });
        return null;
      }
      const content = await file.text();
      logger.debug("Read transcript: {bytes} bytes", { bytes: content.length });
      return content;
    } catch (error) {
      if (attempt < maxRetries) {
        logger.debug("Failed to read transcript (attempt {attempt}), retrying: {error}", {
          attempt,
          error,
        });
        await new Promise((resolve) => setTimeout(resolve, delayMs));
        continue;
      }
      logger.error("Failed to read transcript: {error}", { error });
      return null;
    }
  }
  return null;
}

/**
 * Extract agent IDs referenced in a session transcript.
 * Agents are spawned via the Task tool and their IDs are recorded in toolUseResult.agentId
 */
export function extractAgentIds(sessionContent: string): string[] {
  const agentIds = new Set<string>();

  for (const line of sessionContent.split("\n")) {
    if (!line.trim()) continue;

    try {
      const entry = JSON.parse(line);
      // Agent IDs appear in toolUseResult.agentId when Task tool completes
      if (entry.toolUseResult?.agentId) {
        agentIds.add(entry.toolUseResult.agentId);
      }
    } catch {
      // Skip malformed lines
    }
  }

  const ids = Array.from(agentIds);
  logger.debug("Found {count} subagent(s) in session: {ids}", {
    count: ids.length,
    ids: ids.join(", "),
  });
  return ids;
}

/**
 * Read all subagent files for a session.
 * Subagent transcripts can be stored in multiple locations:
 * 1. {sessionDir}/agent-{agentId}.jsonl (legacy)
 * 2. {sessionDir}/{sessionId}/subagents/agent-{agentId}.jsonl (new format)
 */
export async function readSubagentFiles(
  sessionDir: string,
  agentIds: string[],
  sessionId?: string
): Promise<SubagentFile[]> {
  const subagents: SubagentFile[] = [];

  for (const agentId of agentIds) {
    // Try multiple locations for the subagent file
    const possiblePaths = [
      join(sessionDir, `agent-${agentId}.jsonl`),
      ...(sessionId
        ? [join(sessionDir, sessionId, "subagents", `agent-${agentId}.jsonl`)]
        : []),
    ];

    let found = false;
    for (const agentPath of possiblePaths) {
      try {
        const file = Bun.file(agentPath);
        if (await file.exists()) {
          const content = await file.text();
          subagents.push({ agentId, content });
          logger.debug("Read subagent {agentId}: {bytes} bytes from {path}", {
            agentId,
            bytes: content.length,
            path: agentPath,
          });
          found = true;
          break;
        }
      } catch {
        // Try next path
      }
    }

    if (!found) {
      logger.warn("Subagent file not found for {agentId}", { agentId });
    }
  }

  return subagents;
}

/**
 * Get the repository name for a given directory.
 * Looks for the git root, then reads package.json name or extracts from git remote.
 */
export async function getRepositoryName(cwd: string): Promise<string | null> {
  try {
    // Find git root directory
    const gitRootResult =
      await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
    if (gitRootResult.exitCode !== 0) {
      logger.debug("Not a git repository: {cwd}", { cwd });
      return null;
    }
    const gitRoot = gitRootResult.text().trim();
    logger.info("Git root: {gitRoot}", { gitRoot });

    // Try package.json name first
    const packageJsonPath = join(gitRoot, "package.json");
    const packageFile = Bun.file(packageJsonPath);
    if (await packageFile.exists()) {
      try {
        const packageJson = await packageFile.json();
        if (packageJson.name) {
          logger.debug("Found repository name from package.json: {name}", {
            name: packageJson.name,
          });
          return packageJson.name;
        }
      } catch {
        // Invalid JSON, continue to git remote
      }
    }

    // Fall back to git remote origin URL
    const remoteResult =
      await $`git -C ${gitRoot} remote get-url origin`.quiet();
    if (remoteResult.exitCode === 0) {
      const remoteUrl = remoteResult.text().trim();
      // Extract repo name from various URL formats:
      // - git@github.com:org/repo.git -> repo
      // - https://github.com/org/repo.git -> repo
      // - https://github.com/org/repo -> repo
      const match = remoteUrl.match(/[/:]([^/]+?)(?:\.git)?$/);
      if (match?.[1]) {
        logger.debug("Found repository name from git remote: {name}", {
          name: match[1],
        });
        return match[1];
      }
    }

    // Fall back to directory name
    const dirName = gitRoot.split("/").pop();
    if (dirName) {
      logger.debug("Using directory name as repository: {name}", {
        name: dirName,
      });
      return dirName;
    }

    return null;
  } catch (error) {
    logger.error("Failed to get repository name: {error}", { error });
    return null;
  }
}

/**
 * Get the current git branch name for a given directory.
 */
export async function getGitBranch(cwd: string): Promise<string | null> {
  try {
    const result = await $`git -C ${cwd} rev-parse --abbrev-ref HEAD`.quiet();
    if (result.exitCode !== 0) {
      return null;
    }
    const branch = result.text().trim();
    logger.debug("Git branch: {branch}", { branch });
    return branch;
  } catch (error) {
    logger.error("Failed to get git branch: {error}", { error });
    return null;
  }
}

/**
 * Get the current git commit SHA for a given directory.
 */
export async function getGitSha(cwd: string): Promise<string | null> {
  try {
    const result = await $`git -C ${cwd} rev-parse HEAD`.quiet();
    if (result.exitCode !== 0) {
      return null;
    }
    const sha = result.text().trim();
    logger.debug("Git SHA: {sha}", { sha });
    return sha;
  } catch (error) {
    logger.error("Failed to get git SHA: {error}", { error });
    return null;
  }
}

const VALID_TAGS: SessionTag[] = [
  "research",
  "new_feature",
  "bug_fix",
  "refactoring",
  "documentation",
  "tests",
  "other",
];

/**
 * Classify a session transcript using Claude CLI.
 * Returns one of the predefined tags based on the session content.
 */
export async function classifySession(
  content: string
): Promise<SessionTag | null> {
  const systemPrompt = `You are a session classifier. Analyze the Claude Code session transcript and classify it into exactly ONE of these categories:

- research: Exploring codebase, understanding code, answering questions about how things work
- new_feature: Implementing new functionality or features
- bug_fix: Fixing bugs, errors, or unexpected behavior
- refactoring: Restructuring existing code without changing functionality
- documentation: Writing or updating documentation, comments, READMEs
- tests: Writing, updating, or fixing tests

CRITICAL: Respond with ONLY the tag name. Nothing else. No explanation, no punctuation, no formatting. Just ONE of: research, new_feature, bug_fix, refactoring, documentation, tests`;

  // Truncate content to avoid excessive API costs
  const truncatedContent = content.slice(0, 50000);

  try {
    logger.debug("Classifying session with Claude CLI");

    // Write content to temp file to avoid command-line length limits
    const tempDir = join(homedir(), ".claude", "temp");
    const tempFile = join(tempDir, `classify-${Date.now()}.txt`);
    await Bun.write(tempFile, `Classify this session transcript:\n\n${truncatedContent}`);

    try {
      // IMPORTANT: --no-session-persistence prevents this from triggering SessionEnd hooks recursively
      // Pass the prompt via stdin as Claude CLI expects for --print mode
      const prompt = `Read and classify the session transcript in this file: ${tempFile}`;
      const isWindows = process.platform === "win32";

      // On Windows, need to use shell mode
      const args = isWindows
        ? ["cmd", "/c", `echo ${prompt} | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt "${systemPrompt.replace(/"/g, '\\"')}"`]
        : ["sh", "-c", `echo '${prompt.replace(/'/g, "'\\''")}' | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt '${systemPrompt.replace(/'/g, "'\\''")}'`];

      const proc = Bun.spawn(args, {
        stdout: "pipe",
        stderr: "pipe",
      });

      const exitCode = await proc.exited;
      const stdout = await new Response(proc.stdout).text();
      const stderr = await new Response(proc.stderr).text();

      if (exitCode !== 0) {
        logger.error("Claude CLI failed with exit code {code}, defaulting to 'other': {stderr}", {
          code: exitCode,
          stderr,
        });
        return "other";
      }

      const output = stdout.trim().toLowerCase();

      // First try exact match
      if (VALID_TAGS.includes(output as SessionTag)) {
        logger.info("Session classified as: {tag}", { tag: output });
        return output as SessionTag;
      }

      // If model didn't follow instructions, search for valid tags in output
      // Use word boundaries to avoid partial matches (e.g., "tests" in "testing")
      for (const tag of VALID_TAGS) {
        // Match tag with word boundaries or common delimiters
        const patterns = [
          new RegExp(`\\b${tag}\\b`),           // word boundary
          new RegExp(`[:\`"']${tag}[:\`"']`),   // surrounded by delimiters
          new RegExp(`\\*\\*${tag}\\*\\*`),     // bold markdown
        ];
        if (patterns.some(p => p.test(output))) {
          logger.info("Session classified as: {tag} (extracted from verbose output)", { tag });
          return tag;
        }
      }

      logger.warn("Could not extract valid tag from output, defaulting to 'other': {output}", { output: output.slice(0, 200) });
      return "other";
    } finally {
      // Clean up temp file
      try {
        const { unlink } = await import("fs/promises");
        await unlink(tempFile);
      } catch {
        // Ignore cleanup errors
      }
    }
  } catch (error) {
    logger.error("Failed to classify session, defaulting to 'other': {error}", { error });
    return "other";
  }
}

