### 7. Context Pattern (Dependency Injection)

Stricli supports a context pattern for dependency injection, useful for testing and decoupling:

```typescript
import { buildCommand, type CommandContext } from "@stricli/core";

// Define your context type
interface AppContext {
  readonly process: {
    readonly stdout: NodeJS.WritableStream;
  };
}

const greetCommand = buildCommand({
  docs: { brief: "Greet someone" },
  func: async (this: CommandContext<AppContext>, flags: {}, name: string) => {
    // Access context through `this`
    this.process.stdout.write(`Hello, ${name}!\n`);
  },
  parameters: {
    positional: {
      kind: "tuple",
      parameters: [
        { brief: "Name to greet", parse: String },
      ],
    },
    flags: {},
  },
});
```

When running the application, you provide the context:

```typescript
import { run } from "@stricli/core";
import app from "../app";

run(app, process.argv.slice(2), {
  process: {
    stdout: process.stdout,
  },
});
```

