### 2. Defining Commands with `buildCommand`

Commands are the core unit in Stricli. Each command has a function to run, along with typed parameters (positional arguments and flags).

#### Basic Command with a Single Positional Argument

```typescript
// src/commands/greet.ts
import { buildCommand, type CommandContext } from "@stricli/core";

interface GreetFlags {
  readonly loud: boolean;
}

const greet = buildCommand({
  docs: {
    brief: "Greet someone by name",
  },
  // The function that runs when the command is invoked
  func: async (flags: GreetFlags, name: string) => {
    const greeting = `Hello, ${name}!`;
    if (flags.loud) {
      console.log(greeting.toUpperCase());
    } else {
      console.log(greeting);
    }
  },
  // Define positional arguments
  parameters: {
    positional: {
      kind: "tuple",
      parameters: [
        {
          brief: "Name of the person to greet",
          parse: String,   // Parser function: String, Number, etc.
        },
      ],
    },
    // Define flags (named options)
    flags: {
      loud: {
        kind: "boolean",
        brief: "Print greeting in uppercase",
        optional: true,
        default: false,
      },
    },
  },
});

export default greet;
```

#### Command with Multiple Positional Arguments

```typescript
import { buildCommand } from "@stricli/core";

const addCommand = buildCommand({
  docs: {
    brief: "Add two numbers",
  },
  func: async (flags: {}, a: number, b: number) => {
    console.log(`${a} + ${b} = ${a + b}`);
  },
  parameters: {
    positional: {
      kind: "tuple",
      parameters: [
        {
          brief: "First number",
          parse: Number,
        },
        {
          brief: "Second number",
          parse: Number,
        },
      ],
    },
    flags: {},
  },
});
```

#### Command with Variadic (Rest) Arguments

```typescript
