const concatCommand = buildCommand({
  docs: {
    brief: "Concatenate strings",
  },
  func: async (flags: { separator: string }, ...parts: string[]) => {
    console.log(parts.join(flags.separator));
  },
  parameters: {
    positional: {
      kind: "array",
      parameter: {
        brief: "Strings to concatenate",
        parse: String,
      },
    },
    flags: {
      separator: {
        kind: "parsed",
        brief: "Separator between parts",
        parse: String,
        optional: true,
