  request: IngestRequest,
  config: UploadConfig,
): Promise<UploadResult> {
  const response = await fetch(config.endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": config.apiKey,
    },
    body: JSON.stringify(request),
