#### 3.10 `apps/cli/src/commands/upload.ts`

The main upload command defined with Stricli's `buildCommand`:

```typescript
import { buildCommand, type CommandContext } from "@stricli/core";
import { SESSION_TAGS, DEFAULT_ENDPOINT, type SessionTag } from "../lib/types.js";
import { findSession } from "../lib/session-finder.js";
import { readTranscript } from "../lib/transcript-reader.js";
import { readSubagents } from "../lib/subagent-reader.js";
import { getGitInfo } from "../lib/git-info.js";
import { uploadSession } from "../lib/uploader.js";
import { classifySession } from "../lib/classifier.js";

interface UploadFlags {
  tag?: SessionTag;
  endpoint: string;
  "api-key"?: string;
  classify?: boolean;
  "dry-run"?: boolean;
}

export const uploadCommand = buildCommand({
  async func(this: CommandContext, flags: UploadFlags, sessionId: string) {
    const write = (msg: string) => this.process.stdout.write(msg + "\n");

    // 1. Resolve API key
    const apiKey = flags["api-key"] ?? this.process.env.FLICK_COMPOUND_API_KEY;
    if (!apiKey && !flags["dry-run"]) {
      this.process.stderr.write(
        "Error: API key required. Set FLICK_COMPOUND_API_KEY or use --api-key\n"
      );
      this.process.exitCode = 1;
      return;
    }

    // 2. Find session
    write(`Finding session ${sessionId}...`);
    const session = await findSession(sessionId);
    write(`Found session at: ${session.transcriptPath}`);

    // 3. Read transcript
    write("Reading transcript...");
    const { content, subagentIds } = await readTranscript(session.transcriptPath);
    write(`Transcript: ${content.length} bytes, ${subagentIds.length} subagent(s)`);

    // 4. Read subagents
    const subagents = await readSubagents(subagentIds, session.sessionsDir);

    // 5. Get git info
    const gitInfo = await getGitInfo();

    // 6. Classify if requested
    let tag = flags.tag;
    if (!tag && flags.classify) {
      write("Classifying session...");
      tag = await classifySession(content);
      if (tag) write(`Classified as: ${tag}`);
    }

    // 7. Build request
    const request = {
      sessionId,
      projectPath: session.projectPath,
      repository: gitInfo.repository,
      gitBranch: gitInfo.branch,
      gitSha: gitInfo.sha,
      tag,
      content,
      subagents: subagents.length > 0 ? subagents : undefined,
    };

    // 8. Upload or dry-run
    if (flags["dry-run"]) {
      write("Dry run -- would upload:");
      write(JSON.stringify(request, null, 2));
      return;
    }

    write("Uploading...");
    const result = await uploadSession(request, {
      endpoint: flags.endpoint,
      apiKey: apiKey!,
    });

    if (result.success) {
      write("Upload successful!");
    } else {
      this.process.stderr.write(
        `Upload failed (HTTP ${result.status}): ${JSON.stringify(result.body)}\n`
      );
      this.process.exitCode = 1;
    }
  },
  parameters: {
    positional: {
      kind: "tuple",
      parameters: [
        {
          brief: "The Claude session ID to upload",
          parse: String,
          placeholder: "session-id",
        },
      ],
    },
    flags: {
      tag: {
        kind: "enum",
        values: SESSION_TAGS,
        brief: "Session tag/category",
        optional: true,
      },
      endpoint: {
        kind: "parsed",
        parse: String,
        brief: "Override the upload endpoint URL",
        default: DEFAULT_ENDPOINT,
      },
      "api-key": {
        kind: "parsed",
        parse: String,
        brief: "API key (overrides FLICK_COMPOUND_API_KEY env var)",
        optional: true,
      },
      classify: {
        kind: "boolean",
        brief: "Auto-classify session tag using Claude CLI",
        optional: true,
      },
      "dry-run": {
        kind: "boolean",
        brief: "Preview what would be uploaded without sending",
        optional: true,
      },
    },
  },
  docs: {
    brief: "Upload a Claude Code session transcript to the backend",
  },
});
```

Key Stricli patterns followed:
- `func` uses `this: CommandContext` for accessing `process.stdout`, `process.stderr`, `process.env`, and `process.exitCode`.
- Positional args are a `tuple` with a single `session-id` parameter.
- `tag` is an `enum` flag using the `SESSION_TAGS` constant.
- `endpoint` is a `parsed` flag with a `default` value.
- `api-key` and `classify` and `dry-run` are optional flags.

