## 3. `buildApplication`

**Signature** (from `packages/core/src/application/builder.ts`):

Two overloads:

```typescript
// Overload 1: Single command as root
function buildApplication<CONTEXT extends CommandContext>(
    command: Command<CONTEXT>,
    config: PartialApplicationConfiguration,
): Application<CONTEXT>

// Overload 2: Route map as root
function buildApplication<CONTEXT extends CommandContext>(
    root: RouteMap<CONTEXT>,
    config: PartialApplicationConfiguration,
): Application<CONTEXT>
```

**`PartialApplicationConfiguration` shape** (from `packages/core/src/config.ts`):
```typescript
{
    name: string,                          // REQUIRED -- the CLI executable name
    versionInfo?: {
        currentVersion: string,
        getLatestVersion?: () => Promise<string>,
        upgradeCommand?: string,
    },
    determineExitCode?: (exc: unknown) => number,
    scanner?: Partial<{
        caseStyle: "allow-kebab-for-camel" | /* other styles */,
        distanceOptions: {
            threshold: number,
            weights: { insertion: number, deletion: number, substitution: number, transposition: number },
        },
    }>,
    documentation?: Partial<DocumentationConfiguration>,
    completion?: Partial<CompletionConfiguration>,
    localization?: Partial<LocalizationConfiguration>,
}
```

### Concrete examples from the test suite (`packages/core/tests/application.spec.ts`):

```typescript
import { buildApplication, buildCommand } from "@stricli/core";

// Minimal -- single command
const app = buildApplication(command, {
    name: "cli",
});

// With version info
const app = buildApplication(command, {
    name: "cli",
    versionInfo: {
        currentVersion: "1.0.0",
        getLatestVersion: async () => "1.1.0",
        upgradeCommand: "<upgrade-command>",
    },
});

// Route map as root, with scanner config
const app = buildApplication(routeMap, {
    name: "cli",
    scanner: {
        caseStyle: "allow-kebab-for-camel",
        distanceOptions: {
            threshold: 10,
            weights: {
                insertion: 1,
                deletion: 3,
                substitution: 2,
                transposition: 0,
            },
        },
    },
});
```

