### Build CLI Command with Enum Flag in TypeScript

Source: https://github.com/bloomberg/stricli/blob/main/docs/docs/features/argument-parsing/examples/enum-flag.txt

Creates a CLI command using buildCommand from @stricli/core that accepts an enum flag for logging level selection. The command writes the selected logging level to process stdout. Includes TypeScript interfaces for type safety, flag definitions with enum values, aliases mapping, and command documentation.

```typescript
import { buildCommand, type CommandContext } from "@stricli/core";

interface Flags {
  level: "info" | "warn" | "error";
}

export const root = buildCommand({
  func(this: CommandContext, { level }: Flags) {
    this.process.stdout.write(`Set logging level to ${level}`);
  },
  parameters: {
    flags: {
      level: {
        kind: "enum",
        values: ["info", "warn", "error"],
        brief: "Logging severity level",
      },
    },
    aliases: {
      l: "level",
    },
  },
  docs: {
    brief: "Example for live playground with enum flag"
  },
});
```

--------------------------------

### Build CLI Command with Flags using Stricli (TypeScript)

Source: https://github.com/bloomberg/stricli/blob/main/docs/docs/features/argument-parsing/examples/hidden-flag.txt

Defines a root CLI command using stricli's buildCommand function. It processes 'visible' and 'hidden' boolean flags, writing output to stdout based on flag states. Dependencies include '@stricli/core'. The function takes a Flags object as input and returns nothing.

```typescript
import { buildCommand, type CommandContext } from "@stricli/core";

interface Flags {
  visible?: boolean;
  hidden?: boolean;
}

export const root = buildCommand({
  func(this: CommandContext, { visible, hidden }: Flags) {
    this.process.stdout.write(visible ? "Visible flag active" : "Visible flag inactive");
    if (hidden) {
      this.process.stdout.write("Hidden flag active");
    }
  },
  parameters: {
    flags: {
      visible: {
        kind: "boolean",
        brief: "Visible flag",
        optional: true,
      },
      hidden: {
        kind: "boolean",
        brief: "Hidden flag",
        optional: true,
        hidden: true,
      },
    },
  },
  docs: {
    brief: "Example for live playground with hidden flag"
  },
});
```

