### Build Parsed Flags Command with Stricli Core

Source: https://github.com/bloomberg/stricli/blob/main/docs/docs/features/argument-parsing/examples/parsed-flag.txt

Defines a Stricli command that processes string and number flags. It uses `buildCommand` from `@stricli/core` and expects 'item' and 'price' as parameters. The output is written to stdout.

```typescript
import { buildCommand, numberParser, type CommandContext } from "@stricli/core";

interface Flags {
  item: string;
  price: number;
}

export const root = buildCommand({
  func(this: CommandContext, { item, price }: Flags) {
    this.process.stdout.write(`${item}s cost $${price.toFixed(2)}`);
  },
  parameters: {
    flags: {
      item: {
        kind: "parsed",
        parse: String, // Effectively a no-op
        brief: "Item to display",
      },
      price: {
        kind: "parsed",
        parse: numberParser, // Like Number() but throws on NaN
        brief: "Price of the item",
      },
    },
  },
  docs: {
    brief: "Example for live playground with parsed flags",
    customUsage: [
      "--item apple --price 1",
      "--item orange --price 3.5",
      "--item grape --price 6.25",
    ],
  },
});
```

