import { buildCommand } from "@stricli/core";
import {
	SESSION_TAGS,
	DEFAULT_ENDPOINT,
	type SessionTag,
	type IngestRequest,
} from "../lib/types.js";
import { resolveSession } from "../lib/session-resolver.js";
import {
	readTranscript,
	extractAgentIds,
} from "../lib/transcript-reader.js";
import { readSubagentFiles } from "../lib/subagent-reader.js";
import { getGitInfo } from "../lib/git-info.js";
import { uploadSession } from "../lib/uploader.js";
import { classifySession } from "../lib/classifier.js";

interface UploadFlags {
	readonly tag?: SessionTag;
	readonly endpoint: string;
	readonly "api-key"?: string;
	readonly classify: boolean;
	readonly "dry-run": boolean;
}

export const uploadCommand = buildCommand({
	func: async function (flags: UploadFlags, session: string) {
		const write = (msg: string) => {
			process.stdout.write(`${msg}\n`);
		};
		const writeError = (msg: string) => {
			process.stderr.write(`${msg}\n`);
		};

		// Resolve API key
		const apiKey = flags["api-key"] ?? process.env.FLICK_COMPOUND_API_KEY;
		if (!apiKey && !flags["dry-run"]) {
			writeError(
				"Error: API key required. Set FLICK_COMPOUND_API_KEY or use --api-key",
			);
			process.exitCode = 1;
			return;
		}

		// Resolve session (by ID or path)
		write(`Resolving session: ${session}`);
		let sessionInfo;
		try {
			sessionInfo = await resolveSession(session);
		} catch (error) {
			writeError(`Error: ${error instanceof Error ? error.message : String(error)}`);
			process.exitCode = 1;
			return;
		}
		write(`Found session at: ${sessionInfo.transcriptPath}`);

		// Read transcript
		write("Reading transcript...");
		let content: string;
		try {
			content = await readTranscript(sessionInfo.transcriptPath);
		} catch (error) {
			writeError(`Error reading transcript: ${error instanceof Error ? error.message : String(error)}`);
			process.exitCode = 1;
			return;
		}
		write(`Transcript: ${content.length} bytes`);

		// Extract and read subagents
		const agentIds = extractAgentIds(content);
		let subagents;
		if (agentIds.length > 0) {
			write(
				`Found ${agentIds.length} subagent(s): ${agentIds.join(", ")}`,
			);
			subagents = await readSubagentFiles(
				sessionInfo.sessionDir,
				agentIds,
				sessionInfo.sessionId,
			);
			write(
				`Read ${subagents.length} subagent file(s): ${subagents.reduce((sum, s) => sum + s.content.length, 0)} bytes total`,
			);
		}

		// Get git info
		const gitInfo = await getGitInfo(sessionInfo.projectPath);
		if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
		if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);

		// Classify if requested
		let tag = flags.tag;
		if (!tag && flags.classify) {
			write("Classifying session...");
			tag = (await classifySession(content)) ?? undefined;
			if (tag) write(`Classified as: ${tag}`);
		}

		// Build request
		const request: IngestRequest = {
			sessionId: sessionInfo.sessionId,
			projectPath: sessionInfo.projectPath,
			repository: gitInfo.repository,
			gitBranch: gitInfo.branch,
			gitSha: gitInfo.sha,
			tag,
			content,
			subagents: subagents?.length ? subagents : undefined,
		};

		// Upload or dry-run
		if (flags["dry-run"]) {
			const preview = { ...request, content: `[${request.content.length} bytes]` };
			if (preview.subagents) {
				preview.subagents = preview.subagents.map((s) => ({
					...s,
					content: `[${s.content.length} bytes]`,
				}));
			}
			write("Dry run - would upload:");
			write(JSON.stringify(preview, null, 2));
			return;
		}

		write("Uploading...");
		const result = await uploadSession(request, {
			endpoint: flags.endpoint,
			apiKey: apiKey!,
		});

		if (result.success) {
			write("Upload successful!");
		} else {
			writeError(`Upload failed: ${result.error}`);
			process.exitCode = 1;
		}
	},
	parameters: {
		positional: {
			kind: "tuple",
			parameters: [
				{
					brief: "Session ID or path to a session .jsonl file",
					parse: String,
					placeholder: "session",
				},
			],
		},
		flags: {
			tag: {
				kind: "enum",
				values: [...SESSION_TAGS],
				brief: "Session tag/category",
				optional: true,
			},
			endpoint: {
				kind: "parsed",
				parse: String,
				brief: "Override the upload endpoint URL",
				optional: true,
				default: DEFAULT_ENDPOINT,
			},
