     9→	projectPath: string;
    10→	sessionDir: string;
    11→	sessionId: string;
    12→}
    13→
    14→/**
    15→ * Resolve a session from either a session ID or a full file path.
    16→ * Validates that the file is a main session (not a subagent file).
    17→ */
    18→export async function resolveSession(input: string): Promise<SessionInfo> {
    19→	const isPath = input.includes("/") || input.endsWith(".jsonl");
    20→
    21→	if (isPath) {
    22→		return resolveFromPath(input);
    23→	}
    24→	return resolveFromId(input);
    25→}
    26→
    27→async function resolveFromPath(filePath: string): Promise<SessionInfo> {
    28→	const file = Bun.file(filePath);
    29→	if (!(await file.exists())) {
    30→		throw new Error(`Session file not found: ${filePath}`);
    31→	}
    32→
    33→	const filename = basename(filePath);
    34→	validateNotSubagent(filename);
    35→
    36→	const sessionId = filename.replace(/\.jsonl$/, "");
    37→	const sessionDir = dirname(filePath);
    38→
    39→	// Walk up from sessionDir to find the project directory name
    40→	// Sessions live at: ~/.claude/projects/<encoded-project-dir>/<sessionId>.jsonl
    41→	const parentDir = basename(sessionDir);
    42→	const projectPath = await decodeProjectPath(parentDir);
    43→
    44→	return { transcriptPath: filePath, projectPath, sessionDir, sessionId };
    45→}
    46→
    47→async function resolveFromId(sessionId: string): Promise<SessionInfo> {
    48→	const sessionFileName = `${sessionId}.jsonl`;
    49→
    50→	let projectDirs: string[];
    51→	try {
    52→		projectDirs = await readdir(SESSIONS_BASE_DIR);
    53→	} catch {
    54→		throw new Error(
    55→			`Cannot read sessions directory: ${SESSIONS_BASE_DIR}`,
    56→		);
    57→	}
    58→
    59→	for (const projectDir of projectDirs) {
    60→		const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
    61→		try {
    62→			const files = await readdir(sessionDir);
    63→			if (files.includes(sessionFileName)) {
    64→				const transcriptPath = join(sessionDir, sessionFileName);
    65→				const projectPath = await decodeProjectPath(projectDir);
    66→				return {
    67→					transcriptPath,
    68→					projectPath,
    69→					sessionDir,
    70→					sessionId,
    71→				};
    72→			}
    73→		} catch {
    74→			continue;
    75→		}
    76→	}
    77→
    78→	throw new Error(`Session not found: ${sessionId}`);
    79→}
    80→
    81→function validateNotSubagent(filename: string): void {
    82→	if (filename.startsWith("agent-") && filename.endsWith(".jsonl")) {
    83→		throw new Error(
