		const content = [
			"not-json",
			JSON.stringify({ toolUseResult: { agentId: "valid-agent" } }),
			"{ broken json",
		].join("\n");

		const agentIds = extractAgentIds(content);
		expect(agentIds).toEqual(["valid-agent"]);
	});
});

